import json
import subprocess

# Re-run the first query to extract all 18 events from the raw payload
result = subprocess.run([
    'python3', 'soc-agent/scripts/tools/wazuh_cli.py', 'query',
    '--query', '''{
      "query": {
        "bool": {
          "must":   [{"query_string": {"query": "rule.id:100001 AND data.output_fields.container.name:target-endpoint"}}],
          "filter": [{"range": {"timestamp": {"gte": "now-7d", "lte": "now"}}}]
        }
      }
    }''',
    '--limit', '100',
    '--run-dir', '/tmp/defender-runs/real-03-low-shell',
    '--position', '0d'
], capture_output=False)

# Now extract and analyze the raw payload
with open('/tmp/defender-runs/real-03-low-shell/gather_raw/0d.json', 'r') as f:
    content = f.read()

# The output is markdown; we need to extract the JSON block
if '```json' in content:
    start = content.find('```json') + 7
    end = content.find('```', start)
    json_str = content[start:end].strip()

    try:
        events = json.loads(json_str)

        # Extract cmdline values
        cmdlines = {}
        timestamps = []

        for event in events:
            ts = event.get('timestamp', event.get('@timestamp', 'unknown'))
            timestamps.append(ts)

            cmdline = event.get('data', {}).get('output_fields', {}).get('proc', {}).get('cmdline', 'unknown')
            if cmdline not in cmdlines:
                cmdlines[cmdline] = 0
            cmdlines[cmdline] += 1

        print("\n=== Command Pattern Analysis ===")
        print(f"Total events: {len(events)}")
        print(f"Time span: {min(timestamps)} to {max(timestamps)}")
        print("\nCommand frequencies:")
        for cmd, count in sorted(cmdlines.items(), key=lambda x: -x[1]):
            print(f"  {count}x: {cmd}")
    except json.JSONDecodeError as e:
        print(f"Failed to parse JSON: {e}")
        print("Content snippet:", content[:500])
else:
    print("No JSON block found in output")

