import json
from collections import defaultdict

# Read the tool_trace to find the wazuh_cli output
with open('/tmp/defender-runs/real-03-low-shell/tool_trace.jsonl', 'r') as f:
    for line in f:
        record = json.loads(line)
        if 'wazuh_cli' in str(record.get('tool_name', '')):
            # Found a wazuh_cli invocation
            result = record.get('result', '')
            if '```json' in result:
                # Extract JSON from markdown
                start = result.find('```json') + 7
                end = result.find('```', start)
                if end > start:
                    json_str = result[start:end].strip()
                    try:
                        events = json.loads(json_str)
                        print(f"Found {len(events)} events")

                        # Analyze commands
                        cmdlines = defaultdict(int)
                        for event in events:
                            cmd = event.get('data', {}).get('output_fields', {}).get('proc', {}).get('cmdline', 'N/A')
                            cmdlines[cmd] += 1

                        print("\nCommands found:")
                        for cmd, count in sorted(cmdlines.items(), key=lambda x: -x[1]):
                            print(f"  {count}x: {cmd}")
                    except:
                        pass

